// ─── Karakteristik Envanter — Sheets satirini /api/inventory-tests payload'una cevir ───
const row = $input.first().json;

// Email
const email = String(row['E-Posta Adresin'] || '').toLowerCase().trim();
if (!email) {
  return [{ json: { error: true, message: 'Email bulunamadi', raw_keys: Object.keys(row) } }];
}

// Ad-soyad (sheet'te yoksa null kalir; ileride kolon eklenirse otomatik yakalanir)
const fullName =
  row['Ad Soyad'] || row['Adin Soyadin'] || row['Ad-Soyad'] || row['Ad'] || row['Full Name'] || null;

// Ilgi alanlari — karakteristik formunun ilk secim kolonlari
const interestColumns = ['Yazılım','Dijital Sanatlar','Dijital Pazarlama','Girişimcilik','Kişisel & Kariyer Gelişim'];
const disciplinesInterest = [];
for (const col of interestColumns) {
  const v = row[col];
  if (v !== undefined && v !== null && String(v).trim() !== '' && String(v).trim().toLowerCase() !== 'false') {
    disciplinesInterest.push(col);
  }
}

// Meta alanlari ayikla
const metaKeys = ['#','E-Posta Adresin','Response Type','Start Date (UTC)','Stage Date (UTC)','Submit Date (UTC)','Network ID','Tags','Ending'];
const answers = {};
for (const [k, v] of Object.entries(row)) {
  if (metaKeys.includes(k)) continue;
  if (interestColumns.includes(k)) continue;
  if (v === null || v === undefined || String(v).trim() === '') continue;
  answers[k] = v;
}

const submittedAt = row['Submit Date (UTC)'] || row['Submit Date'] || new Date().toISOString();

return [{
  json: {
    error: false,
    email,
    full_name: fullName ? String(fullName).trim() : null,
    test_type: 'karakteristik_envanter',
    disciplines: disciplinesInterest,
    answers,
    network_id: row['Network ID'] || null,
    tags: row['Tags'] || null,
    response_type: row['Response Type'] || 'completed',
    submitted_at: submittedAt,
  }
}];
